import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"어떤 개발자가 살아남는가","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/books/어떤-개발자가-살아남는가.md","filePath":"outta-space/knowledge/books/어떤-개발자가-살아남는가.md"}'),p={name:"outta-space/knowledge/books/어떤-개발자가-살아남는가.md"};function _(n,a,l,i,s,d){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="어떤-개발자가-살아남는가" tabindex="-1">어떤 개발자가 살아남는가 <a class="header-anchor" href="#어떤-개발자가-살아남는가" aria-label="Permalink to &quot;어떤 개발자가 살아남는가&quot;">​</a></h1><h2 id="_1-핵심-내용" tabindex="-1">1. 핵심 내용 <a class="header-anchor" href="#_1-핵심-내용" aria-label="Permalink to &quot;1. 핵심 내용&quot;">​</a></h2><p>이 책은 AI 시대에 개발자가 어떻게 살아남을 수 있는지를 다룬다.</p><p>책에서 인상 깊었던 주장은 AI에 의해 프로그래머의 상당수는 대체될 수 있지만, 개발자 전체가 사라지는 것은 아니라는 점이다. 단순히 코드를 모방하는 사람보다 창조적으로 문제를 이해하고 해결하는 사람이 살아남는다는 관점이 중심에 있다.</p><p>또한 개발자는 사람을 위한 콘텐츠와 서비스를 만드는 사람이므로, 기술뿐 아니라 사람에 대한 이해도 필요하다고 말한다.</p><h2 id="_2-문체와-가독성" tabindex="-1">2. 문체와 가독성 <a class="header-anchor" href="#_2-문체와-가독성" aria-label="Permalink to &quot;2. 문체와 가독성&quot;">​</a></h2><p>책은 개발자에게 필요한 태도를 직접적인 문장으로 제시한다.</p><p>“걸어라, 읽어라, 써라, 그리고 지금 바로 에디터를 열고 코드를 작성하라” 같은 문장은 다소 선언적이지만, 개발 공부를 미루는 사람에게는 자극이 된다.</p><p>다만 인문학을 해야 한다는 부분은 범위가 너무 넓게 느껴질 수 있다. 개발 입문자에게는 무엇을 얼마나 읽어야 하는지 모호하게 다가올 수 있다.</p><h2 id="_3-저자의-관점과-설득력" tabindex="-1">3. 저자의 관점과 설득력 <a class="header-anchor" href="#_3-저자의-관점과-설득력" aria-label="Permalink to &quot;3. 저자의 관점과 설득력&quot;">​</a></h2><p>저자는 AI 시대에도 개발자가 살아남으려면 단순 구현자가 아니라 문제를 이해하고 사람을 이해하는 창조적 개발자가 되어야 한다고 본다.</p><p>이 관점은 설득력이 있다. AI가 코드를 생성할 수 있게 된 상황에서는 단순 문법 지식이나 반복 구현 능력만으로는 경쟁력이 약해질 수 있기 때문이다.</p><p>다만 개발 지망생에게는 책을 무조건 많이 읽기보다, 현업 개발자가 되었을 때 인문학적 이해가 더 실질적으로 도움이 될 것 같다는 생각도 든다.</p><h2 id="_4-인상-깊은-부분" tabindex="-1">4. 인상 깊은 부분 <a class="header-anchor" href="#_4-인상-깊은-부분" aria-label="Permalink to &quot;4. 인상 깊은 부분&quot;">​</a></h2><p>가장 인상 깊었던 부분은 “프로그래머와 개발자의 차이”에 대한 질문이다.</p><p>프로그래머가 코드를 작성하는 사람에 가깝다면, 개발자는 문제를 정의하고 사용자에게 필요한 결과물을 만드는 사람에 가깝다. 이 차이를 생각하면 AI 시대에 어떤 능력을 길러야 하는지도 조금 더 분명해진다.</p><p>또한 “일반적인 모방보다 창조적 모방을 하는 사람이 살아남는다”는 말도 기억에 남는다. 단순히 따라 하는 것이 아니라, 기존의 것을 이해하고 다른 맥락에 적용할 수 있어야 한다는 뜻으로 받아들였다.</p><h2 id="_5-나에게-남은-생각" tabindex="-1">5. 나에게 남은 생각 <a class="header-anchor" href="#_5-나에게-남은-생각" aria-label="Permalink to &quot;5. 나에게 남은 생각&quot;">​</a></h2><p>이 책을 읽고 개발 공부의 방향을 다시 생각하게 되었다.</p><p>단순히 언어 문법이나 프레임워크 사용법만 익히는 것으로는 부족하다. 결국 중요한 것은 문제를 읽고, 사람을 이해하고, 실제로 코드를 써서 결과물을 만드는 것이다.</p><p>다만 지금 단계에서는 너무 넓은 인문학 공부에 압도되기보다, 개발 공부와 직접 연결되는 읽기와 쓰기부터 시작하는 편이 현실적이라고 느꼈다.</p>',21)])])}const u=e(p,[["render",_]]);export{c as __pageData,u as default};
